  1→package geminicli
  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"os"
  7→
  8→	"github.com/entireio/cli/cmd/entire/cli/agent"
  9→)
 10→
 11→// Transcript parsing types - Gemini CLI uses JSON format for session storage
 12→// Based on transcript_path format: ~/.gemini/tmp/<hash>/chats/session-<date>-<id>.json
 13→
 14→// Message type constants for Gemini transcripts
 15→const (
 16→	MessageTypeUser   = "user"
 17→	MessageTypeGemini = "gemini"
 18→)
 19→
 20→// GeminiTranscript represents the top-level structure of a Gemini session file
 21→type GeminiTranscript struct {
 22→	Messages []GeminiMessage `json:"messages"`
 23→}
 24→
 25→// GeminiMessage represents a single message in the transcript
 26→type GeminiMessage struct {
 27→	ID        string           `json:"id,omitempty"` // UUID for the message
 28→	Type      string           `json:"type"`         // MessageTypeUser or MessageTypeGemini
 29→	Content   string           `json:"content,omitempty"`
 30→	ToolCalls []GeminiToolCall `json:"toolCalls,omitempty"`
 31→}
 32→
 33→// GeminiToolCall represents a tool call in a gemini message
 34→type GeminiToolCall struct {
 35→	ID     string                 `json:"id"`
 36→	Name   string                 `json:"name"`
 37→	Args   map[string]interface{} `json:"args"`
 38→	Status string                 `json:"status,omitempty"`
 39→}
 40→
 41→// ParseTranscript parses raw JSON content into a transcript structure
 42→func ParseTranscript(data []byte) (*GeminiTranscript, error) {
 43→	var transcript GeminiTranscript
 44→	if err := json.Unmarshal(data, &transcript); err != nil {
 45→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
 46→	}
 47→	return &transcript, nil
 48→}
 49→
 50→// ExtractModifiedFiles extracts files modified by tool calls from transcript data
 51→func ExtractModifiedFiles(data []byte) ([]string, error) {
 52→	transcript, err := ParseTranscript(data)
 53→	if err != nil {
 54→		return nil, err
 55→	}
 56→
 57→	return ExtractModifiedFilesFromTranscript(transcript), nil
 58→}
 59→
 60→// ExtractModifiedFilesFromTranscript extracts files from a parsed transcript
 61→func ExtractModifiedFilesFromTranscript(transcript *GeminiTranscript) []string {
 62→	fileSet := make(map[string]bool)
 63→	var files []string
 64→
 65→	for _, msg := range transcript.Messages {
 66→		// Only process gemini messages (assistant messages)
 67→		if msg.Type != MessageTypeGemini {
 68→			continue
 69→		}
 70→
 71→		// Process tool calls in this message
 72→		for _, toolCall := range msg.ToolCalls {
 73→			// Check if it's a file modification tool
 74→			isModifyTool := false
 75→			for _, name := range FileModificationTools {
 76→				if toolCall.Name == name {
 77→					isModifyTool = true
 78→					break
 79→				}
 80→			}
 81→
 82→			if !isModifyTool {
 83→				continue
 84→			}
 85→
 86→			// Extract file path from args map
 87→			var file string
 88→			if fp, ok := toolCall.Args["file_path"].(string); ok && fp != "" {
 89→				file = fp
 90→			} else if p, ok := toolCall.Args["path"].(string); ok && p != "" {
 91→				file = p
 92→			} else if fn, ok := toolCall.Args["filename"].(string); ok && fn != "" {
 93→				file = fn
 94→			}
 95→
 96→			if file != "" && !fileSet[file] {
 97→				fileSet[file] = true
 98→				files = append(files, file)
 99→			}
100→		}
101→	}
102→
103→	return files
104→}
105→
106→// ExtractLastUserPrompt extracts the last user message from transcript data
107→func ExtractLastUserPrompt(data []byte) (string, error) {
108→	transcript, err := ParseTranscript(data)
109→	if err != nil {
110→		return "", err
111→	}
112→
113→	return ExtractLastUserPromptFromTranscript(transcript), nil
114→}
115→
116→// ExtractLastUserPromptFromTranscript extracts the last user prompt from a parsed transcript
117→func ExtractLastUserPromptFromTranscript(transcript *GeminiTranscript) string {
118→	for i := len(transcript.Messages) - 1; i >= 0; i-- {
119→		msg := transcript.Messages[i]
120→		if msg.Type != MessageTypeUser {
121→			continue
122→		}
123→
124→		// Content is now a string field
125→		if msg.Content != "" {
126→			return msg.Content
127→		}
128→	}
129→	return ""
130→}
131→
132→// ExtractAllUserPrompts extracts all user messages from transcript data
133→func ExtractAllUserPrompts(data []byte) ([]string, error) {
134→	transcript, err := ParseTranscript(data)
135→	if err != nil {
136→		return nil, err
137→	}
138→
139→	return ExtractAllUserPromptsFromTranscript(transcript), nil
140→}
141→
142→// ExtractAllUserPromptsFromTranscript extracts all user prompts from a parsed transcript
143→func ExtractAllUserPromptsFromTranscript(transcript *GeminiTranscript) []string {
144→	var prompts []string
145→	for _, msg := range transcript.Messages {
146→		if msg.Type == MessageTypeUser && msg.Content != "" {
147→			prompts = append(prompts, msg.Content)
148→		}
149→	}
150→	return prompts
151→}
152→
153→// ExtractLastAssistantMessage extracts the last gemini response from transcript data
154→func ExtractLastAssistantMessage(data []byte) (string, error) {
155→	transcript, err := ParseTranscript(data)
156→	if err != nil {
157→		return "", err
158→	}
159→
160→	return ExtractLastAssistantMessageFromTranscript(transcript), nil
161→}
162→
163→// ExtractLastAssistantMessageFromTranscript extracts the last gemini response from a parsed transcript
164→func ExtractLastAssistantMessageFromTranscript(transcript *GeminiTranscript) string {
165→	for i := len(transcript.Messages) - 1; i >= 0; i-- {
166→		msg := transcript.Messages[i]
167→		if msg.Type == MessageTypeGemini && msg.Content != "" {
168→			return msg.Content
169→		}
170→	}
171→	return ""
172→}
173→
174→// GetLastMessageID returns the ID of the last message in the transcript.
175→// Returns empty string if the transcript is empty or the last message has no ID.
176→func GetLastMessageID(data []byte) (string, error) {
177→	transcript, err := ParseTranscript(data)
178→	if err != nil {
179→		return "", err
180→	}
181→	return GetLastMessageIDFromTranscript(transcript), nil
182→}
183→
184→// GetLastMessageIDFromTranscript returns the ID of the last message in a parsed transcript.
185→// Returns empty string if the transcript is empty or the last message has no ID.
186→func GetLastMessageIDFromTranscript(transcript *GeminiTranscript) string {
187→	if len(transcript.Messages) == 0 {
188→		return ""
189→	}
190→	return transcript.Messages[len(transcript.Messages)-1].ID
191→}
192→
193→// GetLastMessageIDFromFile reads a transcript file and returns the last message's ID.
194→// Returns empty string if the file doesn't exist, is empty, or has no messages with IDs.
195→func GetLastMessageIDFromFile(path string) (string, error) {
196→	if path == "" {
197→		return "", nil
198→	}
199→
200→	data, err := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
201→	if err != nil {
202→		if os.IsNotExist(err) {
203→			return "", nil
204→		}
205→		return "", fmt.Errorf("failed to read transcript: %w", err)
206→	}
207→
208→	if len(data) == 0 {
209→		return "", nil
210→	}
211→
212→	return GetLastMessageID(data)
213→}
214→
215→// SliceFromMessage returns a Gemini transcript scoped to messages starting from
216→// startMessageIndex. This is the Gemini equivalent of transcript.SliceFromLine —
217→// for Gemini's single JSON blob, scoping is done by message index rather than line offset.
218→// Returns the original data if startMessageIndex <= 0.
219→// Returns nil if startMessageIndex exceeds the number of messages.
220→func SliceFromMessage(data []byte, startMessageIndex int) []byte {
221→	if len(data) == 0 || startMessageIndex <= 0 {
222→		return data
223→	}
224→
225→	t, err := ParseTranscript(data)
226→	if err != nil {
227→		return nil
228→	}
229→
230→	if startMessageIndex >= len(t.Messages) {
231→		return nil
232→	}
233→
234→	scoped := &GeminiTranscript{
235→		Messages: t.Messages[startMessageIndex:],
236→	}
237→
238→	out, err := json.Marshal(scoped)
239→	if err != nil {
240→		return nil
241→	}
242→	return out
243→}
