245→// CalculateTokenUsage calculates token usage from a Gemini transcript.
246→// This is specific to Gemini's API format where each message may have a tokens object
247→// with input, output, cached, thoughts, tool, and total counts.
248→// Only processes messages from startMessageIndex onwards (0-indexed).
249→func CalculateTokenUsage(data []byte, startMessageIndex int) *agent.TokenUsage {
250→	var transcript struct {
251→		Messages []geminiMessageWithTokens `json:"messages"`
252→	}
253→
254→	if err := json.Unmarshal(data, &transcript); err != nil {
255→		return &agent.TokenUsage{}
256→	}
257→
258→	usage := &agent.TokenUsage{}
259→
260→	for i, msg := range transcript.Messages {
261→		// Skip messages before startMessageIndex
262→		if i < startMessageIndex {
263→			continue
264→		}
265→
266→		// Only count tokens from gemini (assistant) messages
267→		if msg.Type != MessageTypeGemini {
268→			continue
269→		}
270→
271→		if msg.Tokens == nil {
272→			continue
273→		}
274→
275→		usage.APICallCount++
276→		usage.InputTokens += msg.Tokens.Input
277→		usage.OutputTokens += msg.Tokens.Output
278→		usage.CacheReadTokens += msg.Tokens.Cached
279→	}
280→
281→	return usage
282→}
283→
284→// CalculateTokenUsageFromFile calculates token usage from a Gemini transcript file.
285→// If startMessageIndex > 0, only considers messages from that index onwards.
286→func CalculateTokenUsageFromFile(path string, startMessageIndex int) (*agent.TokenUsage, error) {
287→	if path == "" {
288→		return &agent.TokenUsage{}, nil
289→	}
290→
291→	data, err := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
292→	if err != nil {
293→		if os.IsNotExist(err) {
294→			return &agent.TokenUsage{}, nil
295→		}
296→		return nil, fmt.Errorf("failed to read transcript: %w", err)
297→	}
298→
299→	return CalculateTokenUsage(data, startMessageIndex), nil
300→}
