  8→func TestParseTranscript(t *testing.T) {
  9→	t.Parallel()
 10→
 11→	// GeminiMessage uses "type" field with values "user" or "gemini"
 12→	data := []byte(`{
 13→  "messages": [
 14→    {"type": "user", "content": "hello"},
 15→    {"type": "gemini", "content": "hi there"}
 16→  ]
 17→}`)
 18→
 19→	transcript, err := ParseTranscript(data)
 20→	if err != nil {
 21→		t.Fatalf("ParseTranscript() error = %v", err)
 22→	}
 23→
 24→	if len(transcript.Messages) != 2 {
 25→		t.Errorf("ParseTranscript() got %d messages, want 2", len(transcript.Messages))
 26→	}
 27→
 28→	if transcript.Messages[0].Type != "user" {
 29→		t.Errorf("First message type = %q, want user", transcript.Messages[0].Type)
 30→	}
 31→	if transcript.Messages[1].Type != "gemini" {
 32→		t.Errorf("Second message type = %q, want gemini", transcript.Messages[1].Type)
 33→	}
 34→}
