 60→func TestExtractModifiedFiles(t *testing.T) {
 61→	t.Parallel()
 62→
 63→	// Gemini transcript with tool calls in ToolCalls array
 64→	data := []byte(`{
 65→  "messages": [
 66→    {"type": "user", "content": "create a file"},
 67→    {"type": "gemini", "content": "", "toolCalls": [{"name": "write_file", "args": {"file_path": "foo.go"}}]},
 68→    {"type": "gemini", "content": "", "toolCalls": [{"name": "edit_file", "args": {"file_path": "bar.go"}}]},
 69→    {"type": "gemini", "content": "", "toolCalls": [{"name": "read_file", "args": {"file_path": "other.go"}}]},
 70→    {"type": "gemini", "content": "", "toolCalls": [{"name": "write_file", "args": {"file_path": "foo.go"}}]}
 71→  ]
 72→}`)
 73→
 74→	files, err := ExtractModifiedFiles(data)
 75→	if err != nil {
 76→		t.Fatalf("ExtractModifiedFiles() error = %v", err)
 77→	}
 78→
 79→	// Should have foo.go and bar.go (deduplicated, read_file not included)
 80→	if len(files) != 2 {
 81→		t.Errorf("ExtractModifiedFiles() got %d files, want 2", len(files))
 82→	}
 83→
 84→	hasFile := func(name string) bool {
 85→		for _, f := range files {
 86→			if f == name {
 87→				return true
 88→			}
 89→		}
 90→		return false
 91→	}
 92→
 93→	if !hasFile("foo.go") {
 94→		t.Error("ExtractModifiedFiles() missing foo.go")
 95→	}
 96→	if !hasFile("bar.go") {
 97→		t.Error("ExtractModifiedFiles() missing bar.go")
 98→	}
 99→}
