186→func TestExtractLastUserPrompt(t *testing.T) {
187→	t.Parallel()
188→
189→	tests := []struct {
190→		name string
191→		data string
192→		want string
193→	}{
194→		{
195→			name: "string content",
196→			data: `{"messages": [
197→				{"type": "user", "content": "first"},
198→				{"type": "gemini", "content": "response"},
199→				{"type": "user", "content": "second"}
200→			]}`,
