260→			data: `{"messages": [
261→				{"type": "user", "content": "hello"},
262→				{"type": "gemini", "content": "hi"}
263→			]}`,
264→			want:    "",
265→			wantErr: false,
266→		},
267→		{
268→			name: "mixed - some with IDs, some without",
