351→func TestGetLastMessageIDFromFile(t *testing.T) {
352→	t.Parallel()
353→
354→	t.Run("empty path", func(t *testing.T) {
355→		t.Parallel()
356→		got, err := GetLastMessageIDFromFile("")
357→		if err != nil {
358→			t.Errorf("GetLastMessageIDFromFile() error = %v", err)
359→		}
