304→// ExtractModifiedFilesFromOffset extracts files modified since a given message index.
305→// For Gemini (JSON format), offset is the starting message index.
306→// Returns:
307→//   - files: list of file paths modified by Gemini (from Write/Edit tools)
308→//   - currentPosition: total number of messages in the transcript
309→//   - error: any error encountered during reading
310→func (g *GeminiCLIAgent) ExtractModifiedFilesFromOffset(path string, startOffset int) (files []string, currentPosition int, err error) {
311→	if path == "" {
312→		return nil, 0, nil
313→	}
314→
315→	data, readErr := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
316→	if readErr != nil {
317→		if os.IsNotExist(readErr) {
318→			return nil, 0, nil
319→		}
320→		return nil, 0, fmt.Errorf("failed to read transcript: %w", readErr)
321→	}
322→
323→	if len(data) == 0 {
324→		return nil, 0, nil
325→	}
326→
327→	transcript, parseErr := ParseTranscript(data)
328→	if parseErr != nil {
329→		return nil, 0, parseErr
330→	}
331→
332→	totalMessages := len(transcript.Messages)
333→
334→	// Extract files from messages starting at startOffset
335→	fileSet := make(map[string]bool)
336→	for i := startOffset; i < len(transcript.Messages); i++ {
337→		msg := transcript.Messages[i]
338→		// Only process gemini messages (assistant messages)
339→		if msg.Type != MessageTypeGemini {
340→			continue
341→		}
342→
343→		// Process tool calls in this message
344→		for _, toolCall := range msg.ToolCalls {
345→			// Check if it's a file modification tool
346→			isModifyTool := false
347→			for _, name := range FileModificationTools {
348→				if toolCall.Name == name {
349→					isModifyTool = true
350→					break
351→				}
352→			}
353→
354→			if !isModifyTool {
355→				continue
356→			}
357→
358→			// Extract file path from args map
359→			var file string
360→			if fp, ok := toolCall.Args["file_path"].(string); ok && fp != "" {
361→				file = fp
362→			} else if p, ok := toolCall.Args["path"].(string); ok && p != "" {
363→				file = p
364→			} else if fn, ok := toolCall.Args["filename"].(string); ok && fn != "" {
365→				file = fn
366→			}
367→
368→			if file != "" && !fileSet[file] {
369→				fileSet[file] = true
370→				files = append(files, file)
371→			}
372→		}
373→	}
374→
375→	return files, totalMessages, nil
376→}
